class Solution:
    def minOperations(self, nums, k):
        def cost(v, r):
            d = (v - r) % k
            return min(d, k - d)

        best = None
        for x in range(k):
            for y in range(k):
                if x == y:
                    continue
                total = 0
                for i, v in enumerate(nums):
                    r = x if i % 2 == 0 else y
                    total += cost(v, r)
                if best is None or total < best:
                    best = total
        return best

