class Solution:
    def minOperations(self, nums, k):
        n = len(nums)
        costEven = [0] * k
        costOdd = [0] * k
        for i, v in enumerate(nums):
            m = v % k
            target = costEven if i % 2 == 0 else costOdd
            for r in range(k):
                d = (m - r) % k
                target[r] += min(d, k - d)
        best = float('inf')
        for x in range(k):
            for y in range(k):
                if x != y:
                    total = costEven[x] + costOdd[y]
                    if total < best:
                        best = total
        return best

