var minOperations = function(nums, k) {
    const n = nums.length;
    const costEven = new Array(k).fill(0);
    const costOdd = new Array(k).fill(0);
    for (let i = 0; i < n; i++) {
        const m = ((nums[i] % k) + k) % k;
        const target = (i % 2 === 0) ? costEven : costOdd;
        for (let r = 0; r < k; r++) {
            const d = (m - r + k) % k;
            target[r] += Math.min(d, k - d);
        }
    }
    let best = Infinity;
    for (let x = 0; x < k; x++) {
        for (let y = 0; y < k; y++) {
            if (x !== y) {
                const total = costEven[x] + costOdd[y];
                if (total < best) best = total;
            }
        }
    }
    return best;
};
